const body = $json.body ?? $json;

const clampCount = (value) => {
  const number = Number(value);
  if (!Number.isFinite(number)) return 3;
  return Math.min(Math.max(Math.round(number), 1), 8);
};

const normalizePriority = (value) => {
  const priority = String(value || 'MEDIUM').trim().toUpperCase();
  return ['HIGH', 'MEDIUM', 'LOW'].includes(priority) ? priority : 'MEDIUM';
};

const taskName = String(body.taskName || body.title || '').trim();
const taskDescription = String(body.taskDescription || body.description || '').trim();
const adminNote = String(body.adminNote || body.note || '').trim();
const sourceInput = String(body.sourceInput || '').trim();
const desiredCount = clampCount(body.desiredCount || body.count || 3);
const priority = normalizePriority(body.priority);
const assigneeEmail = body.assigneeEmail || body.assignedTo || null;
const deadline = body.deadline || body.dueDate || body.endDate || null;

if (!taskName) {
  return [{
    json: {
      ok: false,
      error: 'taskName is required',
      subtasks: []
    }
  }];
}

const contextLines = [
  'Ban la tro ly quan ly du an. Hay chia task cha thanh cac subtask ro rang, co the giao viec truc tiep.',
  '',
  'THONG TIN TASK CHA:',
  'Ten task: ' + taskName,
  'Mo ta: ' + (taskDescription || 'Khong co'),
  'Ghi chu quan ly: ' + (adminNote || sourceInput || 'Khong co'),
  'Do uu tien task cha: ' + priority,
  'Deadline task cha: ' + (deadline || 'Chua co'),
  'Nguoi duoc giao mac dinh: ' + (assigneeEmail || 'Chua co'),
  '',
  'YEU CAU:',
  '- Tao dung ' + desiredCount + ' subtask.',
  '- Moi title phai la hanh dong cu the, ngan gon, tieng Viet, khong trung nhau.',
  '- Khong tao subtask mo ho nhu "Lam task" hoac "Xu ly cong viec".',
  '- Priority chi duoc la HIGH, MEDIUM, LOW. Khong cao hon priority task cha neu khong that su can thiet.',
  '- Status luon la TODO.',
  '- positionIndex bat dau tu 0.',
  '',
  'TRA VE DUY NHAT JSON object dung format nay, khong markdown, khong giai thich:',
  '{"subtasks":[{"title":"...","priority":"MEDIUM","status":"TODO","positionIndex":0}]}'
];

return [{
  json: {
    ok: true,
    taskName,
    taskDescription,
    adminNote,
    sourceInput,
    desiredCount,
    priority,
    assigneeEmail,
    deadline,
    prompt: contextLines.join('\n')
  }
}];

const original = $items('Normalize AI Request')[0]?.json ?? {};
const rawOutput = $json.output ?? $json.text ?? $json.response ?? '';
const fence = String.fromCharCode(96).repeat(3);

const stripFence = (value) => {
  let text = String(value || '').trim();
  const lower = text.toLowerCase();

  if (lower.startsWith(fence + 'json')) {
    text = text.slice((fence + 'json').length).trim();
  } else if (text.startsWith(fence)) {
    text = text.slice(fence.length).trim();
  }

  if (text.endsWith(fence)) {
    text = text.slice(0, -fence.length).trim();
  }

  return text;
};

const normalizePriority = (value) => {
  const priority = String(value || original.priority || 'MEDIUM').trim().toUpperCase();
  if (!['HIGH', 'MEDIUM', 'LOW'].includes(priority)) return original.priority || 'MEDIUM';

  const rank = { LOW: 1, MEDIUM: 2, HIGH: 3 };
  const parentPriority = original.priority || 'MEDIUM';
  return rank[priority] > rank[parentPriority] ? parentPriority : priority;
};

let parsed = null;
try {
  parsed = JSON.parse(stripFence(rawOutput));
} catch (error) {
  parsed = null;
}

const rows = Array.isArray(parsed) ? parsed : (Array.isArray(parsed?.subtasks) ? parsed.subtasks : []);
const seen = new Set();
const subtasks = [];

for (const row of rows) {
  const title = String(row?.title || row?.name || '').trim();
  const key = title.toLowerCase();

  if (!title || seen.has(key)) continue;
  seen.add(key);

  subtasks.push({
    title,
    assignedTo: row?.assignedTo || row?.assigneeEmail || original.assigneeEmail || null,
    deadline: row?.deadline || original.deadline || null,
    priority: normalizePriority(row?.priority),
    status: 'TODO',
    positionIndex: subtasks.length
  });

  if (subtasks.length >= original.desiredCount) break;
}

return [{
  json: {
    ...original,
    ok: subtasks.length > 0,
    needsFallback: subtasks.length === 0,
    subtasks,
    count: subtasks.length,
    rawOutput: String(rawOutput || '')
  }
}];

const original = $items('Normalize AI Request')[0]?.json ?? $json;
const desiredCount = Math.min(Math.max(Number(original.desiredCount || 3), 1), 8);
const titles = [
  'Phan tich yeu cau va pham vi cong viec',
  'Thiet ke phuong an xu ly chi tiet',
  'Trien khai phan viec chinh',
  'Kiem thu va ra soat ket qua',
  'Ban giao va cap nhat tai lieu lien quan',
  'Theo doi phan hoi sau ban giao',
  'Toi uu va xu ly cac diem phat sinh',
  'Tong hop bao cao hoan thanh'
];

const subtasks = titles.slice(0, desiredCount).map((title, index) => ({
  title,
  assignedTo: original.assigneeEmail || null,
  deadline: original.deadline || null,
  priority: original.priority || 'MEDIUM',
  status: 'TODO',
  positionIndex: index
}));

return [{
  json: {
    ...original,
    ok: true,
    needsFallback: false,
    fallbackUsed: true,
    subtasks,
    count: subtasks.length
  }
}];

return [{
  json: {
    ok: $json.ok !== false,
    taskName: $json.taskName,
    priority: $json.priority,
    desiredCount: $json.desiredCount,
    count: Array.isArray($json.subtasks) ? $json.subtasks.length : 0,
    fallbackUsed: Boolean($json.fallbackUsed),
    subtasks: Array.isArray($json.subtasks) ? $json.subtasks : []
  }
}];
